cy.fixture('users').then(users => {
  const user = users.loginUser;
  // ---------------------------
  // Remplir le formulaire de login
  // ---------------------------
  loginPage.emailInput().should('be.visible').type(user.email);
  loginPage.passwordInput().should('be.visible').type(user.password);
  // ---------------------------
  // Cocher "Se souvenir de moi"
  // ---------------------------
  cy.get('[data-testid="checkbox-remember"]').should('be.visible').check().should('be.checked');
  // ---------------------------
  // Se connecter
  // ---------------------------
  loginPage.loginButton().scrollIntoView().click({
    force: true
  });
  // ---------------------------
  // Vérifier connexion réussie
  // ---------------------------
  dashboardPage.dashboardGreeting().should('be.visible').and('contain.text', 'Bonjour');
  // ---------------------------
  // Rafraîchir la page
  // ---------------------------
  cy.reload();
  // ---------------------------
  // Vérifier que l'utilisateur est toujours connecté
  // ---------------------------
  dashboardPage.dashboardGreeting().should('be.visible').and('contain.text', 'Bonjour');
});
